#include <stdio.h>

typedef struct {
    unsigned char Q;      // Current output
    unsigned char Q_bar; // Complement output
    unsigned char D;     // Data input
    unsigned char clk;   // Clock signal
} D_FlipFlop;

void clock_edge(D_FlipFlop *ff) {
    // Detect positive clock edge
    static unsigned char prev_clk = 0;
    if (ff->clk == 1 && prev_clk == 0) {
        ff->Q = ff->D;      // Update output on rising edge
        ff->Q_bar = !ff->D;
    }
    prev_clk = ff->clk;
}

public class FullAdder {
    public static int[] fullAdder(int a, int b, int cin) {
        // Validate inputs
        if ((a < 0 || a > 1) || (b < 0 || b > 1) || (cin < 0 || cin > 1)) {
            throw new IllegalArgumentException("All inputs must be 0 or 1");
        }

        // Sum = A XOR B XOR Cin
        int sum = a ^ b ^ cin;

        // Carry = (A AND B) OR (Cin AND (A XOR B))
        int carryOut = (a & b) | (cin & (a ^ b));

        return new int[]{sum, carryOut};
    }

    public static void main(String[] args) {
        // Test all 8 combinations
        for (int a = 0; a <= 1; a++) {
            for (int b = 0; b <= 1; b++) {
                for (int cin = 0; cin <= 1; cin++) {
                    int[] result = fullAdder(a, b, cin);
                    System.out.printf("%d + %d + %d = Sum:%d, Carry:%d%n", 
                        a, b, cin, result[0], result[1]);
                }
            }
        }
    }
}
